// Прокси: собираем multipart/form-data и шлём в table-merger Python-сервис.
//
// ВАЖНО: n8n 2.17.8 запускает Code-ноду в изолированной VM без глобальных
// fetch / AbortController. helpers.httpRequest (axios) тоже не работает —
// возвращал «Request failed with status code 400» на multipart. Поэтому
// используем встроенный модуль Node.js http через require — это работает
// в sandbox n8n (built-in модули разрешены).

const http = require('http');
const { URL: NodeURL } = require('url');

const MERGER_URLS = [
  { url: 'http://host.docker.internal:8082/merge', timeout: 8000   },
  { url: 'http://127.0.0.1:8082/merge',            timeout: 180000 }
];

const input = $input.first();
const binary = input.binary || {};
const binaryKeys = Object.keys(binary);
console.log('[table-merger] входных binary-полей:', binaryKeys.length, binaryKeys);

if (binaryKeys.length === 0) {
  return [{ json: { success: false, error: 'Не загружено ни одного файла.' } }];
}

// Собираем multipart body руками.
const boundary = '----WebKitFormBoundary' + Math.random().toString(16).slice(2) + Date.now().toString(16);
const chunks = [];
for (const key of binaryKeys) {
  const meta = binary[key];
  const buf = await this.helpers.getBinaryDataBuffer(0, key);
  const filename = (meta.fileName || (key + '.bin')).replace(/"/g, '');
  const contentType = meta.mimeType || 'application/octet-stream';
  chunks.push(Buffer.from('--' + boundary + '\r\n', 'utf8'));
  chunks.push(Buffer.from('Content-Disposition: form-data; name="files"; filename="' + filename + '"\r\n', 'utf8'));
  chunks.push(Buffer.from('Content-Type: ' + contentType + '\r\n\r\n', 'utf8'));
  chunks.push(buf);
  chunks.push(Buffer.from('\r\n', 'utf8'));
}
chunks.push(Buffer.from('--' + boundary + '--\r\n', 'utf8'));
const body = Buffer.concat(chunks);
console.log('[table-merger] multipart body size:', body.length);

// POST через встроенный http модуль. Возвращает {status, headers, body}.
function postMultipart(urlStr, bodyBuffer, boundaryStr, timeoutMs) {
  return new Promise((resolve, reject) => {
    const u = new NodeURL(urlStr);
    const opts = {
      hostname: u.hostname,
      port: u.port || 80,
      path: u.pathname,
      method: 'POST',
      headers: {
        'Content-Type': 'multipart/form-data; boundary=' + boundaryStr,
        'Content-Length': bodyBuffer.length
      },
      timeout: timeoutMs
    };
    const req = http.request(opts, (res) => {
      const parts = [];
      res.on('data', (c) => parts.push(c));
      res.on('end', () => resolve({
        status: res.statusCode,
        headers: res.headers,
        body: Buffer.concat(parts)
      }));
      res.on('error', reject);
    });
    req.on('error', reject);
    req.on('timeout', () => { req.destroy(new Error('timeout after ' + timeoutMs + 'ms')); });
    req.write(bodyBuffer);
    req.end();
  });
}

let response = null;
let usedUrl = '';
let lastErrMsg = '';
for (const entry of MERGER_URLS) {
  try {
    const r = await postMultipart(entry.url, body, boundary, entry.timeout);
    console.log('[table-merger] http', entry.url, 'status:', r.status, 'bodySize:', r.body.length);
    if (r.status >= 200 && r.status < 300) {
      response = r;
      usedUrl = entry.url;
      break;
    }
    // 4xx/5xx — сервис ответил, но это ошибка. Прокидываем пользователю.
    let errMsg = 'HTTP ' + r.status;
    try {
      const txt = r.body.toString('utf8');
      const parsed = JSON.parse(txt);
      if (parsed && parsed.detail) errMsg = parsed.detail;
      else if (txt) errMsg = txt.slice(0, 500);
    } catch (_) {
      const txt = r.body.toString('utf8');
      if (txt) errMsg = txt.slice(0, 500);
    }
    return [{ json: { success: false, error: errMsg } }];
  } catch (e) {
    lastErrMsg = (e && e.message) ? e.message : String(e);
    console.log('[table-merger] http error на', entry.url, ':', lastErrMsg);
    continue;
  }
}

if (!response) {
  return [{ json: { success: false, error: 'table-merger сервис недоступен. Запусти start.bat на хост-машине (порт 8082). Последняя ошибка: ' + lastErrMsg } }];
}

const cd = response.headers['content-disposition'] || '';
const respContentLength = response.headers['content-length'] || '';
console.log('[table-merger] response content-length:', respContentLength, '| content-disposition:', cd);

let outFilename = 'merged.bin';
let m = cd.match(/filename\*=UTF-8''([^;]+)/i);
if (m) {
  try { outFilename = decodeURIComponent(m[1]); } catch (_) { outFilename = m[1]; }
} else {
  m = cd.match(/filename="?([^";]+)"?/i);
  if (m) outFilename = m[1];
}
const outMime = response.headers['content-type'] || 'application/octet-stream';

const outBuffer = response.body;
console.log('[table-merger] outBuffer size:', outBuffer.length);

if (outBuffer.length === 0) {
  return [{ json: { success: false, error: 'Пустой ответ от Python-сервиса (' + usedUrl + '). content-length: ' + respContentLength + '.' } }];
}

const binaryData = await this.helpers.prepareBinaryData(outBuffer, outFilename, outMime);

return [{
  json: {
    success: true,
    filename: outFilename,
    size: outBuffer.length,
    files: binaryKeys.length,
    debug: { usedUrl: usedUrl, respContentLength: respContentLength }
  },
  binary: { data: binaryData }
}];
